// decode_filter_audio.c - فك ترميز + تطبيق فلاتر صوتي
#include <libavcodec/avcodec.h>
#include <libavformat/avformat.h>
#include <libavfilter/avfilter.h>
#include <libavfilter/buffersrc.h>
#include <libavfilter/buffersink.h>
#include <stdio.h>

int main(int argc, char **argv) {
    const char *filename = argc > 1 ? argv[1] : "input.mp3";

    // فتح المدخل
    AVFormatContext *fmt_ctx = NULL;
    avformat_open_input(&fmt_ctx, filename, NULL, NULL);
    avformat_find_stream_info(fmt_ctx, NULL);

    int stream_idx = av_find_best_stream(fmt_ctx, AVMEDIA_TYPE_AUDIO, -1, -1, 0, NULL);
    const AVCodec *codec = avcodec_find_decoder(fmt_ctx->streams[stream_idx]->codecpar->codec_id);
    AVCodecContext *codec_ctx = avcodec_alloc_context3(codec);
n    avcodec_parameters_to_context(codec_ctx, fmt_ctx->streams[stream_idx]->codecpar);
n    avcodec_open2(codec_ctx, codec, NULL);

    // بناء graph الفلاتر: abuffer -> volume=2.0 -> aformat=sample_fmts=flt:44100 -> abuffersink
    AVFilterGraph *graph = avfilter_graph_alloc();
    int ret = avfilter_graph_parse_ptr(graph,
        "abuffer=time_base=1/44100:sample_rate=44100:channel_layout=stereo"
        "[volume=2.0]"
        "[aformat=sample_fmts=flt:sample_rate=44100]"
        "abuffersink",
        NULL);
    if (ret < 0) {
        fprintf(stderr, "فشل بناء graph\n");
        return 1;
    }
    avfilter_graph_config(graph, NULL);

    // قراءة وفك الترميز وتطبيق الفلتر
    AVFrame *frame = av_frame_alloc();
    AVPacket *pkt = av_packet_alloc();
    AVFrame *filt_frame = av_frame_alloc();

    while (av_read_frame(fmt_ctx, pkt) >= 0) {
        if (pkt->stream_index == stream_idx) {
            avcodec_send_packet(codec_ctx, pkt);
            while (avcodec_receive_frame(codec_ctx, frame) >= 0) {
                // إدخال frame إلى graph الفلاتر
                ret = av_buffersrc_add_frame(graph, frame);
                if (ret < 0) break;
                // استخراج الناتج من graph
                while (av_buffersink_get_frame(graph, filt_frame) >= 0) {
                    // filt_frame يحتوي البيانات بعد تطبيق volume=2.0
                    printf("filtered: samples=%d\n", filt_frame->nb_samples);
                }
            }
        }
        av_packet_unref(pkt);
    }

    av_frame_free(&frame);
    av_frame_free(&filt_frame);
    av_packet_free(&pkt);
n    avcodec_free_context(&codec_ctx);
n    avformat_close_input(&fmt_ctx);
n    avfilter_graph_free(&graph);
    return 0;
}

